const items = [];
const binaryData = $input.item.binary;

// 遍歷所有以 doc_file_ 開頭或編號的二進位欄位
for (const key of Object.keys(binaryData)) {
  items.push({
    json: { 
      // 保留原始檔名，這對後續寫入試算表與 Pinecone Metadata 至關重要
      fileName: binaryData[key].fileName 
    },
    binary: {
      // 強制將所有檔案重新命名為 doc_file，對齊後方節點設定
      doc_file: binaryData[key]
    }
  });
}

return items;

