// 1. 抓取所有 Google Drive 的檔案 (假設節點名稱為 Google Drive Trigger)
const driveFiles = $("Search files and folders").all();

// 2. 抓取所有 Google Sheets 的紀錄 (假設節點名稱為 Get row(s) in sheet)
const sheetRows = $("Get row(s) in sheet4").all();

// 3. 將試算表中的檔名建立成一個 Set (提高比對效率)
const existingFileNames = new Set(sheetRows.map(row => row.json.FileName));

// 4. 過濾：只保留「檔名不在試算表裡」的檔案
return driveFiles.filter(file => !existingFileNames.has(file.json.name));

// 1. 抓取雲端硬碟目前的檔案 (假設節點名稱為 Download file)
const driveFiles = $("Search files and folders").all();

// 2. 抓取試算表目前的紀錄 (假設節點名稱為 Get row(s) in sheet4)
const sheetRows = $("Get row(s) in sheet4").all();

// 3. 建立雲端硬碟現有檔名的集合 (提高搜尋速度)
const currentDriveFileNames = new Set(driveFiles.map(file => file.json.name));

// 4. 過濾：保留「在試算表裡，但不在雲端硬碟中」的紀錄
const missingFromDrive = sheetRows.filter(row => !currentDriveFileNames.has(row.json.FileName));

// 5. 回傳結果，這將作為後續 Pinecone 刪除節點的輸入
return missingFromDrive;
